INSERT INTO public.photos VALUES (21273, '&quot;Ambos Mundos&quot; c.1900', '"Zaragoza: Caf├® de Ambos Mundos". Tarjeta postal que reproduce el original exterior del edificio del Paseo Independencia, que ocupa toda la manzana entre el paseo, y las calles Casa Jim├®nez (derecha), Ponzano, traseras, y Albareda (izquierda). Era mundialmente conocido porque en sus bajos estaba ubicado desde 1881 el "Gran Caf├® de Ambos Mundos", ah├¡ es nada. En 1928 este edificio ser├í intensamente reformado, por fuera, y por dentro. Fuente: Fot. Laurent (Madrid), AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64922800, -0.88416200, '0101000020E6100000E1B54B1B0E4BECBFE1D231E719D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22645585436.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22645585436.webp', 'https://www.flickr.com/photos/zaragozaantigua/22645585436/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21337, 'Teatro Gran Casino 1908', 'Teatro del Gran Casino en la Exposici├│n Hispano-Francesa de 1908, huerta de Santa Engracia..', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53816006627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53816006627.webp', 'https://www.flickr.com/photos/zaragozaantigua/53816006627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21342, 'Restaurante Gran Casino 1908', 'Restaurante del Gran Casino en la Exposici├│n Hispano-Francesa de 1908, huerta de Santa Engracia..', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817182728.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817182728.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817182728/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21346, 'Quiosco Confiteros 1908', 'Quiosco de la Asociaci├│n de Confiteros en la Exposici├│n Hispano-Francesa de 1908, huerta de Santa Engracia.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64844800, -0.87992500, '0101000020E61000007FD93D795828ECBF0C94145800D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53817321054.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53817321054.webp', 'https://www.flickr.com/photos/zaragozaantigua/53817321054/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21466, 'Palacio de la M├║sica 1911', 'Imagen capturada durante la inauguraci├│n oficial de la Exposici├│n Regional de Bellas Artes alojada en el "Palacio de la M├║sica". Este evento fue organizado por la Secci├│n de Artes del Ateneo Cient├¡fico y Literario de Zaragoza, cuyo presidente, Sr. Marqu├®s de Arlanza, dio el discurso inaugural ante un selecto auditorio de personalidades encabezado por el arzobispo Soldevila, el gobernador civil Eduardo Garc├¡a Bajo, el gobernador militar Sr. Salcedo, el presidente de la Audiencia Territorial Sr. Marqu├®s de Santa Amalia, el rector de la Universidad Sr. Gim├®nez Soler y el vicepresidente de la Diputaci├│n Sr. Sancho Arroyo. Esta exposici├│n ten├¡a por objeto la promoci├│n del arte regional, con la presencia de 177 obras de escultores y pintores aragoneses, algunos noveles y prometedores como el escultor Antonio Torres Clavero y los pintores Julio Garc├¡a Condoy y Ram├│n Ac├¡n Aquilu├®, adem├ís de figuras consagradas como Juan Jos├® G├írate. La entrada normal costaba 30 c├®ntimos, que se reduc├¡a a 15 los domingos, y ascend├¡a a una peseta cuando se programaban atracciones suplementarias destinadas a la "gente bien" de mayor poder adquisitivo, como los "d├¡as de moda", "fiestas aristocr├íticas con un five ├│clok tea chocolat", conciertos y t├│mbolas. Este Palacio de la M├║sica hab├¡a sido proyectado por el arquitecto Ricardo Magdalena para la Exposici├│n Hispano-Francesa de 1908, fue luego reformado para albergar espect├ículos y eventos varios hasta su demolici├│n postrera para urbanizar el entorno de la plaza de Castelar.', 1911, 1911, 1911, 'Anos 10', 'CENTRO', 41.64922600, -0.88035400, '0101000020E61000009BE3DC26DC2BECBF40DB6AD619D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457533823.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457533823.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457533823/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21515, 'Plaza de Castelar 1922', 'Miguel Faci Abad. 1922. "Zaragoza. Casa de la familia Castellano en la plaza de Castelar." Imagen de la casa de Tom├ís Castellano Echenique en la plaza de Castelar, esquina con la calle de Costa (a la izquierda). Este edificio de vivienda, ecl├®ctico en sus formas, es dise├▒o de Teodoro R├¡os. A├▒os despu├®s ser├í adquirido por una entidad local de ahorro, que desde 1935 utiliz├│ los bajos para dispensario sanitario, hasta que en 1999 quiso ser reconvertido en "Espacio Goya", pero se qued├│ en centro cultural. Fuente visual: "Miguel y Gabriel Faci. Fot├│grafos fundadores de la Real Sociedad Fotogr├ífica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci├│n Provincial de Zaragoza, 1999.', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15741820995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15741820995.webp', 'https://www.flickr.com/photos/zaragozaantigua/15741820995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21530, 'Falla 1920', 'Primera falla valenciana levantada en Zaragoza, por parte de la comunidad de valencianos afincados en la ciudad. Representa la futura l├¡nea f├®rrea que unir├í las dos ciudades. Al fondo, la portada de la iglesia de Santa Engracia. Fuente: La Hormiga de Oro, 1920.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64926600, -0.88294000, '0101000020E610000053910A630B41ECBFCE33F6251BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18984321460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18984321460.webp', 'https://www.flickr.com/photos/zaragozaantigua/18984321460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21563, 'Gran Hotel 1929', 'Imagen del nov├¡simo Gran Hotel, con su caracter├¡stico chafl├ín, unos d├¡as antes de su inauguraci├│n oficial, cuando ofertaba 200 habitaciones y la "pensi├│n completa" m├¡nima alcanzaba las 22,50 pesetas. A su derecha, solar sobre el que unos a├▒os despu├®s ser├í levantado el actual n┬║ 7 de la calle Costa. A su izquierda, el original colegio "Nuestra Se├▒ora del Pilar" de la Compa├▒├¡a de Santa Teresa de Jes├║s. Fuente: revista "Estampa" (Madrid).', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22549409958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22549409958.webp', 'https://www.flickr.com/photos/zaragozaantigua/22549409958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21606, 'Calle Costa 1926', '"Proyecto de casas propiedad de do├▒a Carmen Yarza y don Valent├¡n de Torres Solanot", Regino Borobio, 1926. Dibujo del edificio de viviendas racionalista de la calle de Joaqu├¡n Costa 5 y 7 (hoy 9 y 11). Fue terminado en 1928. A la derecha, fuera de plano, se encuentra el patio del antiguo dispensario antituberculoso de la plaza de los Sitios. Fuente visual: "Regino Borobio Ojeda, 1895-1976", Jos├® Manuel Pozo Municio, Colegio Oficial de Arquitectos de Arag├│n, 1991, a trav├®s de www.facebook.com/photo.php?fbid=665218510309483&set=p...', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.64870300, -0.88074100, '0101000020E6100000FCE1E7BF072FECBF96E82CB308D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27944770554.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27944770554.webp', 'https://www.flickr.com/photos/zaragozaantigua/27944770554/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21635, 'Calle del Arquitecto Magdalena 1927', 'Imagen desde cierta altura del reci├®n terminado inmueble del n┬║ 10 de la calle de Felipe Sanclemente, proyectado por Teodoro R├¡os Balaguer para Tom├ís Castellano y Echenique, esquinero con la plaza de Castelar, a la derecha y fuera de plano. En primer t├®rmino, su gran patio con fuente e ingreso por el n┬║ 13 de la calle de Joaqu├¡n Costa, de igual superficie que el edificio. A la izquierda, y en la calle de Isaac Peral, se destaca la chimenea de El├®ctricas Reunidas de Zaragoza y las traseras del Teatro Circo. A la derecha y al fondo, el panorama despejado de inmediatas edificaciones nos lleva hasta las traseras del n┬║ 14 de la calle de San Miguel.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64876900, -0.88011800, '0101000020E6100000A4DE5339ED29ECBF4ED4D2DC0AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49762506842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49762506842.webp', 'https://www.flickr.com/photos/zaragozaantigua/49762506842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21637, 'Calle de Joaqu├¡n Costa c.1927', 'Imagen capturada desde cierta altura en el inmueble del n┬║ 12 de la calle de Joaqu├¡n Costa, con vista del panorama edilicio de esta calle en el lado de los impares desde el inmueble del n┬║ 9, en primer t├®rmino, pasando por los solares de los n├║meros 7 y 5, donde poco despu├®s se levantar├¡a el Gran Hotel. Tras el cruce con la calle de Isaac Peral destaca el destacado y reciente inmueble del n┬║ 3, construido para el general S├íinz Mend├¡vil, A su derecha aparece, de repente, la c├║pula de la iglesia parroquial de Santiago el Mayor. Hacia el fondo, la plaza de santa Engracia y el principio de la calle, con la enorme casa del conde de La Rosa, esquinera con el paseo de la Independencia. Tras ├®l, la calle del marqu├®s de Casa Jim├®nez.', 1927, 1927, 1927, 'Anos 20', 'CENTRO', 41.64905700, -0.88165200, '0101000020E6100000E97E4E417E36ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50768170792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50768170792.webp', 'https://www.flickr.com/photos/zaragozaantigua/50768170792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21700, 'P.┬║ de la Independencia 1936', 'Ni Guerra Civil ni nada. En Zaragoza, para las fiestas del Pilar, a sacar a los gigantes, aunque llueva lo que llueva. No obstante, Don Quijote no las tiene todas consigo y otea el horizonte por si las moscas. Detr├ís, en el edificio esquina con Albareda, el colegio de la Sagrada Familia, por supuesto. Fuente: www.facebook.com/photo.php?fbid=883970591636022&set=o...', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15566994358.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15566994358.webp', 'https://www.flickr.com/photos/zaragozaantigua/15566994358/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21798, 'P.┬║ de la Independencia 1931', 'Postal, Roisin. Vista de la acera de los pares del paseo de la Independencia, con la plaza de Arag├│n a la espalda. Tras la calle de Albareda, el edificio del Banco de Cr├®dito de Zaragoza reformado por Pascual Bravo, y en cuyos bajos estaba el caf├® Ambos Mundos. A la derecha, el cenotafio "A los funcionarios muertos en agosto de 1920". Fuente: www.ebay.com/', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64894400, -0.88429300, '0101000020E6100000849D62D5204CECBFBC77D49810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25503955481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25503955481.webp', 'https://www.flickr.com/photos/zaragozaantigua/25503955481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21799, 'Isaac Peral 1931', 'Fotograf├¡a de Lucien Roisin. Imagen del achaflanado cruce entre las calles Isaac Peral y Costa, uno de los espacios reurbanizados tras la Exposici├│n de 1908 en la que fuera antigua huerta del convento de Santa Engracia. En primer plano, el nov├¡simo Gran Hotel, con notable flota de autom├│viles, como reflejo del exclusivo signo social de la clientela. A su derecha, las vallas indican que su solar vecino va a ser pronto obrado. Hacia el fondo, en Peral, el tambi├®n reciente nuevo recinto para el convento y colegio de las Teresianas. A su izquierda, la poderosa chimenea de la f├íbrica de electricidad de Electra Peral, en el cruce con la calle San Miguel. Inmediato, y a la derecha y posiblemente con dise├▒o de Teodoro R├¡os Balaguer, el desaparecido edificio entre Peral y Costa, sustituido al poco por otro nuevo, menos clasicista, y m├ís vertical, que de eso se trataba.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25600514522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25600514522.webp', 'https://www.flickr.com/photos/zaragozaantigua/25600514522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21856, 'P.┬║ Independencia 1934', 'Imagen capturada desde cierta altura y centrada en el inmueble del n┬║ 31 del paseo de la Independencia, construido a finales del siglo XIX. A la izquierda. el moderno edificio de la casa de Tel├®fonos. A la derecha, el emboque a la calle de Bruil, con vista parcial del hotelito sede del Gobierno Civil. Sobre los soportales del paseo, el anuncio comercial luminoso que se├▒alaba la presencia de la reconocida sastrer├¡a de Justo Gimeno, con sus talleres de corte y confecci├│n, almac├®n y tienda de ropa. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CENTRO', 41.64890700, -0.88377500, '0101000020E610000080B74082E247ECBF9F9273620FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36102859260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36102859260.webp', 'https://www.flickr.com/photos/zaragozaantigua/36102859260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21886, 'P.┬║ de la Independencia 1939', 'Imagen capturada durante un desfile militar por el paseo de la Independencia, posiblemente durante los actos de homenaje al Cuerpo de Ej├®rcito de Arag├│n. A la izquierda, soportales o porches del paseo bajo el original edificio de Tel├®fonos. Al fondo y luminosa, la plaza de Arag├│n, donde tuvieron lugar la misa de campa├▒a y los discursos de homenaje.', 1939, 1939, 1939, 'Anos 30', 'CENTRO', 41.64918600, -0.88382000, '0101000020E6100000809F71E14048ECBFB282DF8618D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49666311411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49666311411.webp', 'https://www.flickr.com/photos/zaragozaantigua/49666311411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22120, 'Salvador Dal├¡ 1956', 'Salvador Dal├¡ (1904-1989) pernoct├│ en el Gran Hotel de Zaragoza el 15 de mayo de 1956, procedente de Nueva York y acompa├▒ado de su esposa Gala y de Gonzalo Serraclara, abogado y familiar del pintor. Al d├¡a siguiente, el periodista de Heraldo de Arag├│n Marcial Buj le abord├│ en el hall para hacerle una entrevista, que se public├│ el jueves 17 de mayo. Su meta era Santiago de Compostela, tras pasar por Madrid y el sur de la pen├¡nsula. Seg├║n el catal├ín, ÔÇ£Zaragoza es piramidal, s├│lida, realista y eternaÔÇØ. En la puerta del hotel (calle de Joaqu├¡n Costa 5), Miguel Mar├¡n Chivite les hizo unas fotos. En los cristales se ven reflejados los edificios de los n├║meros 2 y 4 de la calle Costa. Fuente visual: "Chas, de Salduba a las Vegas", Eduardo Laborda, 2015.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64898400, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF4AD05FE811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22537046801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22537046801.webp', 'https://www.flickr.com/photos/zaragozaantigua/22537046801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22214, 'Calle de Juan Bruil 1959', 'Imagen tomada en la calle de Juan Bruil y centrada en la fachada del Hotel Centenario, habilitado en 1940 donde estuviera originalmente el Gran Hotel Regina. Fue reformado en 1942, y derribado en 1966 para mayor aprovechamiento vertical del espacio. Al fondo, el inmueble del n┬║ 10 del paseo de Marina Moreno. En la puerta del hotel destaca un Renault 4/4 construido en la factor├¡a Fasa-Espa├▒a de Valladolid. A la derecha e inmediato, el anexo hotelito del n┬║ 1 de la plaza de Arag├│n que albergara hasta 1958 el Gobierno Civil. Fuente visual: AMZ.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.64843700, -0.88361800, '0101000020E61000008E0585419946ECBF1842CEFBFFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46158723854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46158723854.webp', 'https://www.flickr.com/photos/zaragozaantigua/46158723854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22290, 'Plaza de Arag├│n 1969', 'Cuatro funcionarios p├║blicos recorren diariamente las calles de Zaragoza cumpliendo su importante misi├│n: los carteros de Zaragoza. No son los "Fab Four", pero en tiempos en que la "net" era apenas una especulaci├│n, el correo postal ordinario ten├¡a importancia capital. En la imagen, cargados con su labor del d├¡a, cuatro carteros cruzan el paseo de la Independencia en el linde con la plaza de Arag├│n. A la derecha, en la esquina con la calle Bruil, vallas comerciales anuncian el piqueteo del antiguo hotelito que fuera sede del Gobierno Civil, y de las anexas edificaciones que fueran del antiguo hotel Regina, y la construcci├│n de la actual y macizada manzana con viviendas, y nuevo hotel. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CENTRO', 41.64882000, -0.88410200, '0101000020E61000008D800A47904AECBFD07EA4880CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15254348204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15254348204.webp', 'https://www.flickr.com/photos/zaragozaantigua/15254348204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22334, 'Avenida Independencia c.1962', '"Avenida de la Independencia". Postal. En 1961 se transform├│ el paseo de la Independencia de Zaragoza en avenida, aunque acab├│ conservando la denominaci├│n anterior. Una vez terminadas las obras, el cenotafio "A los funcionarios muertos en agosto de 1920" permaneci├│ all├¡ por un tiempo, hasta que fue trasladado a su ubicaci├│n actual, en el paseo de Marina Moreno. La foto est├í tomada desde la plaza de Arag├│n. Fuente visual: www.todocoleccion.net/', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64900800, -0.88419600, '0101000020E6100000E620E868554BECBFD36BB3B112D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19331723976.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19331723976.webp', 'https://www.flickr.com/photos/zaragozaantigua/19331723976/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22491, 'Paseo Independencia 1964', 'Vista nocturna del paseo de la Independencia desde la plaza de Arag├│n. A la derecha, el Cenotafio "La ciudad honra a sus funcionarios" (1924). Fuente: Foto Mar├¡n Chivite. Revista Triunfo.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46303011945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46303011945.webp', 'https://www.flickr.com/photos/zaragozaantigua/46303011945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22527, 'Plaza de Arag├│n 1972', 'Un convoy del tranv├¡a de la l├¡nea 5 Plaza Espa├▒a-Venecia atraviesa la plaza de Arag├│n. Al fondo, el paseo de la Independencia. Interesante visual del antiguo hotelito de la plaza esquinado con la calle Albareda, previa a su piqueteo en el tr├ínsito neodemocr├ítico. Fuente visual: www.flickr.com/photos/jhm0284/5812546885/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64879300, -0.88438800, '0101000020E6100000F4311F10E84CECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700732400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700732400.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700732400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22727, 'Plaza Arag├│n 1972', 'Foto centrada en la unidad 325 de la l├¡nea 30 de los autobuses urbanos, "Casablanca". Est├í situado en la plaza de Arag├│n. Tras el autob├║s, el edificio de Capitan├¡a. Fuente visual: foto J-H. Manara, en www.flickr.com/photos/jhm0284/5813113284/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64848500, -0.88459400, '0101000020E6100000419C8713984EECBF2979758E01D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30566346233.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30566346233.webp', 'https://www.flickr.com/photos/zaragozaantigua/30566346233/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22730, 'P.┬║ de la Independencia 1972', 'Foto centrada en la unidad 162 de la l├¡nea 21 de los autobuses urbanos, "Plaza del Pilar-Barrio Oliver". Est├í a punto de entrar en la plaza de Arag├│n. Tras el autob├║s, la entrada a la calle de Jos├® Luis Albareda desde el paseo de la Independencia. Fuente visual: foto J-H. Manara, en www.flickr.com/photos/jhm0284/5812544705/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64891800, -0.88443300, '0101000020E6100000F419506F464DECBF93E4B9BE0FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31004431580.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31004431580.webp', 'https://www.flickr.com/photos/zaragozaantigua/31004431580/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22850, 'Vista desde Santa Engracia 1987', 'Luis M├¡nguez. 1987. La torre de la iglesia de Santa Engracia desde la que se captura esta imagen se asienta sobre la cripta de los "Innumerables m├írtires de Zaragoza", que son 18 contados, as├¡ que la visual tampoco da para mucho m├ís que una miradica a la inmediata plaza de Santa Engracia, al paseo de la Independencia, y a la calle Marqu├®s de Casa Jim├®nez, donde el antiguo Gobierno Militar, y el reciente hotel de cinco estrellas, en cuyos bajos hab├¡a dos cines, dos, y en cuyos bajos m├ís bajos, tal vez un anfiteatro romano, dicen. A la izquierda, el edificio de Correos y Tel├®grafos.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.64905700, -0.88294000, '0101000020E610000053910A630B41ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15233392993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15233392993.webp', 'https://www.flickr.com/photos/zaragozaantigua/15233392993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22961, 'Jordi Pujol 1983', 'Imagen capturada en la puerta del Gran Hotel y centrada en Jordi Pujol Soley, presidente de la Generalitat de Catalunya, charla campechanamente con unos soldados de reemplazo que realizaban el Servicio Militar Obligatorio en Zaragoza. La presencia del "Molt Honorable" en la ciudad ten├¡a como objeto asistir a la final de la Copa del Rey de F├║tbol que disputaron el s├íbado 4 de junio de 1983 los equipos del F.C. Barcelona y del Real Madrid C.F. en el estadio municipal de la Romareda, y que finaliz├│ con el resultado de 2 tantos (V├¡ctor Mu├▒oz y Marcos Alonso) a 1 (Santillana) a favor del F.C. Barcelona. De tel├│n de fondo, el inmueble del n┬║ 3 de la calle de Joaqu├¡n Costa, chaflanero con la calle de Isaac Peral.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64903300, -0.88174900, '0101000020E610000087FBC8AD4937ECBF2C836A8313D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53248420638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53248420638.webp', 'https://www.flickr.com/photos/zaragozaantigua/53248420638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22965, 'Dispensario antituberculoso a├▒os 90', 'Calle Costa, 13 con plaza de los Sitios. Inaugurado en 1935 como dispensario antituberculoso, en 1952 se transform├│ en t├®trico dispensario para enfermedades del t├│rax, hasta que se clausur├│ en 1997. En 1999 fue propuesto como sede del Espacio Goya, proyecto que se desestim├│. Hoy es Ibercaja Zentrum, lugar de actividades culturales. Fuente: Ibercaja', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14831880089.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14831880089.webp', 'https://www.flickr.com/photos/zaragozaantigua/14831880089/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23050, 'Plaza de Arag├│n 1991', 'Imagen capturada en la plaza de Arag├│n con una vista parcial, a la izquierda, de las jardineras instaladas durante el reciente embellecimiento de este espacio urbano, que adem├ís ejerc├¡an de estilosos quitamiedos decorados con azulejos que formaban los escudos de las tres provincias y capitales provinciales, por aquello de hacer honor a la plaza donde estaban radicados. As├¡, en esta escena aparece el tradicional escudo municipal de Zaragoza. Hacia el fondo que conduce al paseo de la Independencia, una de las paradas de autob├║s de la plaza, en las que se pod├¡an acumular varios veh├¡culos de las diferentes l├¡neas que por aqu├¡ transitaban.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.64852000, -0.88454900, '0101000020E610000042B456B4394EECBFA5660FB402D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50441653682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50441653682.webp', 'https://www.flickr.com/photos/zaragozaantigua/50441653682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23649, 'Cuartel de Santa Engracia 1906', 'Dibujo de Ambrosio Ruste que representa la entrada del Cuartel de Infanter├¡a de Santa Engracia, antes aprobarse su derribo en 1906 (aunque s├│lo se har├í efectivo un par de a├▒os despu├®s). A la izquierda, junto a la peque├▒a casa de vecinos, el t├║nel que comunicaba con la Huerta de Santa Engracia. A la derecha, la iglesia de Santa Engracia. Fuente: ┬íAqu├¡... Zaragoza!, Jos├® Blasco Ijazo, 1952.', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.64921700, -0.88268300, '0101000020E61000007F86376BF03EECBFED80EB8A19D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19644875760.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19644875760.webp', 'https://www.flickr.com/photos/zaragozaantigua/19644875760/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23664, 'Cuartel de Santa Engracia 1908', 'Imagen de Casta├▒er-O├▒a realizada durante los festejos que celebraban el comienzo del derribo del antiguo cuartel de Santa Engracia. Aunque esto estaba previsto desde al menos 1906, tras importantes debates, su cesi├│n al ayuntamiento por parte del Gobierno de Espa├▒a s├│lo fue aprobada a finales de enero de 1908, y el comienzo del derribo, a finales de marzo de ese a├▒o. Tras el ceremonial que acompa├▒├│ a la desmilitarizaci├│n del lugar, y la reubicaci├│n del regimiento "Arag├│n", que all├¡ se alojaba, en el cercano cuartel de Hern├ín Cort├®s, la comparsa de gigantes y cabezudos, autoridades, y una multitud de personas, se citaron por la tarde del 30 de marzo para celebrar el hecho, a la zaragozana manera. La imagen, capturada desde cierta altura, captura esto. A la derecha, inmediata y fuera de plano, queda la iglesia de Santa Engracia y la calle de la Ronda. A la izquierda, un callej├│n daba acceso a la huerta de Santa Engracia, en obras por la Expo de 1908. Tras el derribo de los edificios de la imagen, y durante el proceso de urbanizaci├│n de los terrenos de la Exposici├│n Hispano-Francesa, por aqu├¡ se abrir├ín las nuevas calles de Joaqu├¡n Costa y Don Hernando de Arag├│n. Fuente: Revista "Nuevo Mundo"', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64904000, -0.88243700, '0101000020E6100000A5F8F884EC3CECBFDEE522BE13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27014339404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27014339404.webp', 'https://www.flickr.com/photos/zaragozaantigua/27014339404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23674, 'Cuartel de Santa Engracia 1908', 'Interesante imagen capturada en uno de los tres grandes patios interiores del antiguo cuartel de Santa Engracia (el oriental), poco antes de su derribo, tras ser vendido al Ayuntamiento para incorporar este gran recinto al proyecto de urbanizaci├│n de la antigua huerta de Santa Engracia. En primer plano, uno de los grandes pabellones cuarteleros. A la izquierda, acceso al patio noroeste, al que se ingresaba desde la plaza de Santa Engracia por la oscura puerta del fondo. M├ís a la izquierda emerge la torre oriental de la iglesia parroquial de Santa Engracia. Fuente visual: revista "La Ilustraci├│n Militar".', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64880900, -0.88217800, '0101000020E6100000A305685BCD3AECBFDC2C5E2C0CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33508601555.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33508601555.webp', 'https://www.flickr.com/photos/zaragozaantigua/33508601555/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24019, 'Calle Costa 1975', 'Entrada de la "Librer├¡a P├│rtico" en la calle de Joaqu├¡n Costa n┬║ 2. En agosto de 1975, se produjo una explosi├│n en este establecimiento, causando importantes da├▒os materiales. El propietario, Jos├® Alcrudo, hubo de soportar ├®ste y otros m├ís en su Librer├¡a P├│rtico de la plaza de San Francisco. Las sospechas apuntaron a grupos ultraderechistas interrelacionados, como la CEDADE, la editorial Fuerza Nueva o la Sociedad Cultural Covadonga. Casualmente, esta librer├¡a ten├¡a en sus escaparates libros sobre la Segunda Rep├║blica y la guerra de 1936-39, tal vez algo desviados de la doctrina del R├®gimen, y d├¡as antes del atentado, dos j├│venes entraron a la librer├¡a para que distribuyera ejemplares del panfleto de Jorge Mota titulado "Hacia un socialismo europeo: ┬┐Falange o comunismo?", a lo que el propietario les dijo: NO. La editora del panfleto era "BAU", as├¡ denominada por el activista de al derecha extrema Ram├│n Bau, primero de CEDADE, que luego deriv├│ hacia el C├¡rculo de Estudios Indoeuropeos, y m├ís recientemente, al apoyo a los c├¡rculos editoriales del nazismo europeo, como la cruzada de la Librer├¡a Europa, de Barcelona. Hasta bien entrados los a├▒os ochenta, los atentados fascistas continuaron en Zaragoza. Fuente: Agencia EFE.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.64911200, -0.88205000, '0101000020E610000044FAEDEBC039ECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24624011965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24624011965.webp', 'https://www.flickr.com/photos/zaragozaantigua/24624011965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24040, 'Asamblea Municipalista 1906', 'Entre el 9 y el 11 de febrero de 1906, en el teatro Pignatelli, tuvo lugar la Asamblea Municipalista de Zaragoza, donde se reunieron personalidades de la antigua corona de Arag├│n vinculadas con la gesti├│n de los ayuntamientos desde un punto de vista republicano. Por parte local, participaron activamente Marceliano Is├íbal, y Jos├® Gasc├│n y Mar├¡n. Entre las conclusiones realizadas, destacaban la reivindicaci├│n de la autonom├¡a municipal, de una hacienda municipal independiente de la provincial y nacional, de la municipalizaci├│n de los servicios p├║blicos, de la necesidad de un patrimonio municipal, de dar batalla al caciquismo, y de la jornada laboral de ocho horas para los trabajadores de los ayuntamientos. La medalla conmemorativa de la imagen, en bronce, fue esculpida por Parera/Rodr├¡guez, y en el anverso figura el busto aleg├│rico de la Rep├║blica, con una Marianne a la espa├▒ola; en el reverso, una composici├│n con las alegor├¡as de la Libertad, la Igualdad, y la Fraternidad. Fuente visual: www.museunacional.cat/', 1906, 1906, 1906, 'Anos 1900', 'CENTRO', 41.64914000, -0.88337800, '0101000020E61000003C3080F0A144ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30688545041.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30688545041.webp', 'https://www.flickr.com/photos/zaragozaantigua/30688545041/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24072, 'P.┬║ de la Independencia 1918', 'Posado de aristocr├íticas muchachas vestidas de gala a la usanza tradicionalista durante la celebraci├│n del D├¡a de la Flor de ese a├▒o, donde postulaban fondos para la asistencia a los tuberculosos pobres de la ciudad. La imagen ha sido capturada en el andador central del paseo de la Independencia, en la zona frontera ya con la plaza de Arag├│n, donde se ha habilitado un ef├¡mera tribuna decorada con motivos vegetales, visible parcialmente a la derecha. Fuente visual: foto S├ínchez Rom├ín para diario ABC, en abcfoto.abc.es/', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.64896300, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF33A8363811D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34400249342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34400249342.webp', 'https://www.flickr.com/photos/zaragozaantigua/34400249342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24086, 'Plaza Arag├│n 1916', 'Vista de la plaza de Arag├│n, con el Gobierno Civil en su n├║mero 1 (centro). A la izquierda, calle de Bruil, y a la derecha, el hotelito con el n├║mero 2. Hasta ah├¡ llega una manifestaci├│n "para entregar el mensaje de protesta de las clases productoras".', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64878200, -0.88431300, '0101000020E61000004BAFCDC64A4CECBFE21DE0490BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43613097381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43613097381.webp', 'https://www.flickr.com/photos/zaragozaantigua/43613097381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24091, 'P.┬║ de la Independencia 1936', 'Imagen capturada en el paseo de la Independencia durante el desfile del Tercio de Do├▒a Mar├¡a de las Nieves de requet├®s navarros reci├®n llegados desde Pamplona para reforzar en Zaragoza la sublevaci├│n militar contra la Segunda Rep├║blica Espa├▒ola tras el 19 de julio de 1936. La llegada de estos combatientes se produjo el 23-24 de julio tras la iniciativa de Jes├║s Muro Sevilla, jefe local de Falange, que viaj├│ a Pamplona y propici├│ el env├¡o de un contingente de unos 1.200 requet├®s navarros, que llegaron a la ciudad en ferrocarril por la Estaci├│n del Norte, y que luego fueron reubicados en funci├│n de las necesidades de los sublevados. Fueron tambi├®n la base sobre la que se constituy├│ la organizaci├│n local del requet├® aragon├®s. La escena tiene lugar en ├║ltimo tramo del antiguo paseo de la Independencia, llegando ya casi a la plaza de Arag├│n. En el centro, la calle de Jos├® Luis Albareda, flanqueada a la izquierda por el hotelito del n┬║ 13 de la plaza de Arag├│n, y a la derecha por el gran inmueble del paseo en cuyos bajos estaba el Caf├® Ambos Mundos (a la derecha, fuera de plano), el esquinero comercio Casa Polo de confecciones y tejidos, y la oficina donde entonces se ubicaba el "Institut Fran├ºais". En 1940 el Ayuntamiento decidi├│ conmemorar estos hechos, redenominando la calle del Cinco de Marzo como Requet├® Aragon├®s, y dando el nombre de Requet├® Navarro a un vial en Las delicias que conectaba las avenidas de Madrid y de Navarra.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64894200, -0.88433500, '0101000020E61000003FA9F6E9784CECBF1B800D8810D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47268546201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47268546201.webp', 'https://www.flickr.com/photos/zaragozaantigua/47268546201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24101, 'Plaza de Santa Engracia c.1937', 'Ins├│lita imagen capturada ante la puerta de la iglesia parroquial de Santa Engracia con un posado grupal realizado tras una ceremonia de boda celebrada en su interior, en el que destaca el jefe provincial de Falange, Jes├║s Muro Sevilla, que acompa├▒a a la joven pareja reci├®n casada, falangista ella, falangista ├®l.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64910600, -0.88288600, '0101000020E6100000871403249A40ECBF96D1C8E715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51178200016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51178200016.webp', 'https://www.flickr.com/photos/zaragozaantigua/51178200016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24106, 'Calle de Joaqu├¡n Costa 1937', 'Imagen capturada en la calle de Joaqu├¡n Costa y ante el Gran Hotel, durante la recepci├│n que los jefes de Falange Espa├▒ola Tradicionalista de las JONS organizaron con motivo de la visita a Zaragoza de una delegaci├│n de las Juventudes Hitlerianas llegadas desde Alemania y que recorrieron diversas localidades de la Espa├▒a nacionalista y algunos frentes de batalla. En el centro de la fotograf├¡a destaca la presencia de Jes├║s Muro, jefe territorial de FET-JONS, y a su lado Jes├║s Com├¡n, su Secretario de Organizaci├│n. A la derecha, miembros de la colonia alemana en Zaragoza, del colegio y consulado alemanes. Detr├ís de todos ellos, centurias de FET-JONS, Cadetes y Pelayos, que contaban con el acompa├▒amiento de bandas de m├║sica y la habitual parafernalia de emblemas y banderas falangistas y nacionalsocialistas. Al fondo, la calle de Isaac Peral.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.64903300, -0.88174900, '0101000020E610000087FBC8AD4937ECBF2C836A8313D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51783816152.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51783816152.webp', 'https://www.flickr.com/photos/zaragozaantigua/51783816152/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24117, 'Paseo de la Independencia 1916', 'En el balc├│n del primer piso del hotelito del n┬║ 13 de la plaza de Arag├│n, una in├®dita captura para ilustrar la "manifestaci├│n de las clases productoras" convocada el 10 de mayo de 1916 para protestar contra el Gobierno de la naci├│n, en medio de una importante crisis de subsistencias agravada por la coyuntura b├®lica de la Gran Guerra. La manifestaci├│n hab├¡a comenzado en la plaza de la Libertad y estaba prevista su finalizaci├│n ante el Gobierno Civil sito en la plaza de Arag├│n, donde se le entreg├│ un mensaje al gobernador civil Juan Zab├¡a Bernad. En la imagen, el cortejo transita por el paseo de la Independencia, llegando a la altura de la calle de Jos├® Luis Albareda, destacando cinco pancartas con una curiosa mezcolanza de mensajes: "El monopolio de los transportes anula la soberan├¡a popular", "Queremos ahora la unificaci├│n de tarifas", "Exigiremos despu├®s la nacionalizaci├│n de los ferrocarriles", "El arancel ha sido un seguro para la ineptitud de los sider├║rgicos" y "┬í┬íQuien paga manda, Se├▒or Conde, hay que gobernar!!" (referencia al Conde de Romanones, Presidente del Consejo de Ministros). Fuera de imagen y a la derecha quedaba la pancarta que abr├¡a la manifestaci├│n: "┬í┬íPol├¡ticos, escoged!! O las empresas explotadoras o el pueblo que no quiere explotadores". Hacia el fondo y a la derecha, luminosa presencia del gran inmueble del bar├│n de la Rosa en el n┬║ 29 del paseo, esquinero con la plaza de Santa Engracia. En el contrastado fondo edilicio se destacan en altura las torres de la Seo y de la iglesia de San Gil Abad. En primer t├®rmino y a la izquierda, pegados en los porches del n┬║ 32 del paseo, dos carteles convocando junta general extraordinaria "A los alba├▒iles y peones asociados y no asociados" y "A los obreros pintores en general", reflejo tambi├®n de la conflictividad social que caracterizaba el mundo del trabajo, que el a├▒o siguiente conocer├¡a la convocatoria de una Huelga General.', 1916, 1916, 1916, 'Anos 10', 'CENTRO', 41.64917000, -0.88414100, '0101000020E610000003B00111E24AECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52777590061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52777590061.webp', 'https://www.flickr.com/photos/zaragozaantigua/52777590061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24152, '&quot;Expo 1908&quot;, 1907', 'Despejada imagen realizada por Casta├▒er-O├▒a, que captura un instante de los trabajos preparatorios en los terrenos de la exposici├│n Hispano-Francesa de 1908, en la que fuera huerta de Santa Engracia, as├¡ denominada por formar parte del antiguo, Real y enorme monasterio jer├│nimo de ese nombre. En este caso concreto, se trata de la obra de cimentaci├│n del emblem├ítico "Pabell├│n Franc├®s", en la zona suroeste del recinto. Al fondo, traseras de los edificios de la calle San Miguel, entre los que destaca la chimenea de la el├®ctrica ubicada entre las calles Porcell y Blancas. Fuente visual: Revista "Nuevo Mundo"', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64885900, -0.88124300, '0101000020E610000094861A852433ECBF8E5BCCCF0DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27617995885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27617995885.webp', 'https://www.flickr.com/photos/zaragozaantigua/27617995885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24270, 'Claustro de Santa Engracia 1844', 'Dibujo de Jenaro P├®rez Villaamil, sobre un croquis de Mariano Carderera, incluido luego en la obra "Espa├▒a art├¡stica y monumental vistas y descripci├│n de los sitios y monumentos m├ís notables de Espa├▒a". Fuente visual: Fondo Documental Hist├│rico de las Cortes de Arag├│n.', 1844, 1844, 1844, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14691195229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14691195229.webp', 'https://www.flickr.com/photos/zaragozaantigua/14691195229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24275, 'Convento de Santa Engracia 1813', 'Ruinas del Real Monasterio de Santa Engracia, destruido parcialmente en los Sitios. En la imagen, aspecto visto desde la orilla derecha del r├¡o Huerva, al otro lado del puente de Santa Engracia. Fuente visual: Edward Hawke Locker, London, 1824', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874498102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874498102.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874498102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24283, 'Monasterio de Santa Engracia 1809', 'Episode du si├¿ge de Saragosse : assaut du monast├¿re de San Engracia, le 8 f├®vrier 1809 (Asalto del Monasterio de Santa Engracia el 8 de febrero de 1809), Louis-Fran├ºois Lejeune, 1827. Desde 1808, Espa├▒a hab├¡a establecido una compleja y amarga guerra contra los ocupantes franceses, animada por un fuerte sentido religioso (Napole├│n fue se├▒alado como enemigo del catolicismo), din├ístico (apego a los Borbones), y nacionalista (odio contra el ocupante extranjero) . Despu├®s de una victoria bastante f├ícil sobre las tropas regulares espa├▒olas, los franceses toparon con la presencia de una fuerza expedicionaria brit├ínica y los "guerrilleros" ind├¡genas, que les obligaron a mantener numerosas tropas de ocupaci├│n. Despu├®s de un inicial fracaso, el ej├®rcito franc├®s conquist├│ Zaragoza. En la imagen, Lejeune retrata el "Asalto del monasterio de San Engracia", donde captura la furia de la lucha entre el ej├®rcito franc├®s y los defensores de Zaragoza. Al fondo torre de la Enfermer├¡a conventual, y claustro grande del Monasterio de Santa Engracia, en la Huerta de Santa Engracia. Fuente: www.histoire-image.org/pleincadre/index.php?i=333', 1809, 1809, 1809, 'Siglo XIX', 'CENTRO', 41.64876200, -0.87993100, '0101000020E61000000892770E6528ECBF9B711AA20AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15176001446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15176001446.webp', 'https://www.flickr.com/photos/zaragozaantigua/15176001446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24286, 'Monasterio de Santa Engracia 1737', '"Descripci├│n o mapa del Real Monasterio y Parroquia de Santa Engracia de Zaragoza", dibujo incluido en el libro "Origen y Antig├╝edades del Subterr├íneo y celeb├®rrimo Santuario de Sta. Mar├¡a de las Santas Masas" (Le├│n Benito Mart├│n, Zaragoza, 1737). Vista de los terrenos del Monasterio de Santa Engracia de Zaragoza, con el r├¡o Huerva en primer plano y la inclusi├│n de otros edificios conventuales cercanos, como el de las Madres Capuchinas, a la izquierda, o el de las Monjas de Santa Catalina, arriba a la derecha. En el centro, a la izquierda, la Puerta de Santa Engracia, situada en el entorno del actual paseo de la Independencia. Fuente: ifc.dpz.es/recursos/publicaciones/32/30/09morte.pdf', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64896100, -0.87984900, '0101000020E6100000BF620D17B927ECBF92B06F2711D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458717915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458717915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458717915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24289, 'Calle Joaqu├¡n Costa 1928', 'Postal, foto Jal├│n, 1928. "Nueva Zaragoza. Calle de Costa". Esta imagen, en direcci├│n al Paseo de la Independencia, no era tan contestada como la vista hacia el Paseo de la Mina, en que al final se ve├¡a el enorme dep├│sito de "El Gas". Esa otra vista no ten├¡a tanta "clase". Fuente de la imagen: Foto Jal├│n, en todocolecci├│n.net.', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64911400, -0.88227400, '0101000020E61000002A8E03AF963BECBF18B0E42A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15640401851.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15640401851.webp', 'https://www.flickr.com/photos/zaragozaantigua/15640401851/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24292, 'Ruinas de Santa Engracia 1813', 'As├¡ luc├¡an las ruinas del convento de Santa Engracia en una gu├¡a de viaje inglesa de 1880 titulada "Spanish pictures drawn with pen and pencil", si bien era una copia, con sus licencias y modificaciones, del dibujo que Eduard Hanke Locker hab├¡a realizado en 1813. Para los editores de la obra, ilustrar con im├ígenes de hac├¡a 67 a├▒os una obra actual, era normal. Como con la literatura oral, una copia de una copia puede acabar modificando bastante la realidad que pretende capturar. Las fuentes orales, y los dibujos, son as├¡.', 1813, 1813, 1813, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15765993029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15765993029.webp', 'https://www.flickr.com/photos/zaragozaantigua/15765993029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24302, 'Espacio Goya 1999', 'Recreaci├│n virtual del proyecto de Basilio Tob├¡as para instalar en 1999 el Espacio Goya en la antigua casa de Tom├ís Castellano construida por Teodoro R├¡os en la Calle Costa 13 de Zaragoza. Fue desestimado por Ibercaja, la empresa promotora, que en 2015 redenomin├│ con el nombre del pintor el Museo Cam├│n Aznar, tras un intento fallido en 2006 de instalar el Espacio Goya en los edificios de la Escuela de Artes y el Museo de Zaragoza. Fuente visual: www.basiliotobias.com/', 1999, 1999, 1999, 'Anos 90', 'CENTRO', 41.64855500, -0.88024900, '0101000020E610000047C66AF3FF2AECBF2254A9D903D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19301307914.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19301307914.webp', 'https://www.flickr.com/photos/zaragozaantigua/19301307914/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24309, 'Santa Engracia 1737', '"Portada de Alabastro de la Yglesia de Sta. Engracia", dibujo incluido en el libro "Historia del subterr├íneo Santuario oy Real Monasterio de Sta. Engracia de Zaragoza. Origen y Antig├╝edades del Subterr├íneo y celeb├®rrimo Santuario de Sta. Mar├¡a de las Santas Masas", escrito por el Padre Fray Le├│n Benito Mart├│n y Aznar (Zaragoza, 1737). El notable inter├®s de este dibujo radica en que es una de las escasas representaciones de la original fachada del Monasterio, con sus "mud├®jares" torres y remate, adem├ís de su renacentista portada, antes de convertirse en uno de los desastres de la guerra de 1808-1809 primero, y de la posguerra despu├®s. Fuente visual: Biblioteca Digital Hisp├ínica bdh.bne.es/', 1737, 1737, 1737, 'Siglo XIX', 'CENTRO', 41.64908500, -0.88268800, '0101000020E6100000F14A92E7FA3EECBF7EA99F3715D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19779039645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19779039645.webp', 'https://www.flickr.com/photos/zaragozaantigua/19779039645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24312, 'Claustro de Santa Engracia 1808', '"Ruinas del patio de Santa Engracia, causadas por la explosi├│n del 13 de agosto de 1808". Serie Ruinas de Zaragoza, de Juan G├ílvez (dibujo) y Fernando Brambila (grabado), C├ídiz, 1812. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64854400, -0.88261300, '0101000020E610000047C8409E5D3EECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20550964379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20550964379.webp', 'https://www.flickr.com/photos/zaragozaantigua/20550964379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24316, 'Santa Engracia 1866', 'Iglesia de Santa Engracia. A la izquierda, garita del cuartel hom├│nimo. Fuente: Mariano J├║dez y Ortiz. Colecci├│n Boisset-Ib├í├▒ez. Libro Primeros tiempos de la fotograf├¡a en Zaragoza.', 1866, 1866, 1866, 'Siglo XIX', 'CENTRO', 41.64916800, -0.88288700, '0101000020E61000009E08E23C9C40ECBF0CCEE0EF17D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27966267604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27966267604.webp', 'https://www.flickr.com/photos/zaragozaantigua/27966267604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
